let
  # We define the entire set of session variables once in this let block.
  sessionVariables = let
    qtDependencies = with pkgs; [
      qt6.qtwayland
      qt6.qtsvg
      qt6.qt5compat
      qt6.qtdeclarative
      qt6.qtpositioning
      qt6.qtmultimedia
      qt6.qtquicktimeline
      qt6.qtimageformats
      qt6.qtvirtualkeyboard
      qt6.qtsensors
      qt6.qttools
      qt6.qttranslations
      qt6.qtwebsockets
      qt6.qtshadertools
      qt6.qtscxml
      kdePackages.kirigami.unwrapped
      kdePackages.kirigami-addons
      kdePackages.breeze-icons
      kdePackages.qqc2-desktop-style
      kdePackages.syntax-highlighting
    ];
  in
  {
      QML2_IMPORT_PATH = pkgs.lib.concatMapStringsSep ":" (pkg: "${pkg}/lib/qt-6/qml:${pkg}/lib/qml") qtDependencies + ":${config.home.homeDirectory}/.config/quickshell/ii";
      QML_IMPORT_PATH = pkgs.lib.concatMapStringsSep ":" (pkg: "${pkg}/lib/qt-6/qml:${pkg}/lib/qml") qtDependencies + ":${config.home.homeDirectory}/.config/quickshell/ii";
      QT_PLUGIN_PATH = pkgs.lib.concatMapStringsSep ":" (pkg: "${pkg}/lib/qt-6/plugins:${pkg}/lib/plugins") qtDependencies;
      # wayland/hyprland/quickshell variables
      XDG_CURRENT_DESKTOP = "Hyprland";
      XDG_SESSION_TYPE = "wayland";
      XDG_SESSION_DESKTOP = "Hyprland";
      QT_QPA_PLATFORM = "wayland";
      QT_WAYLAND_DISABLE_WINDOWDECORATION = "1";
      QT_AUTO_SCREEN_SCALE_FACTOR = "1";
      GDK_BACKEND = "wayland,x11";
      SDL_VIDEODRIVER = "wayland";
      CLUTTER_BACKEND = "wayland";
      # Wayland support for Electron/Chromium
      NIXOS_OZONE_WL = "1";
      # nvidia specific 
      LIBVA_DRIVER_NAME = "nvidia";
      GBM_BACKEND = "nvidia-drm";
      __NV_PRIME_RENDER_OFFLOAD = "1";
      __GLX_VENDOR_LIBRARY_NAME = "nvidia";
    };

in
# This now returns a single, valid attribute set.
{
  # We assign the set we defined above to both options.
  home = {
    sessionVariables = sessionVariables;
      pointerCursor = {
        package = pkgs.bibata-cursors-translucent;
        name = "Bibata-Modern-Translucent";
        size = 24;
        gtk.enable = true;
        x11.enable = true;
      };
  };
  systemd = {
    user = {
      sessionVariables = sessionVariables;
      services.matugen = {
        Unit.Description = "Declarative Matugen Color Engine";
        Service = {
          # NOTE: Path updated. Ensure a wallpaper exists at this location in /persist.
          ExecStart = "${pkgs.matugen}/bin/matugen apply -i /persist/home/nondeus/Pictures/wallpaper.png";
          Type = "oneshot";
        };
      };
    };
  };
}

Web search results for "nix-cachyos-kernel nvidia nixos configuration":

To configure **NixOS** with the **CachyOS kernel** and **NVIDIA drivers**, you should use the `nix-cachyos-kernel` flake.[1] This repository provides pre-patched kernels and a binary cache to avoid long compilation times.[1]

### 1. Flake Setup (`flake.nix`)
Add the `nix-cachyos-kernel` flake to your inputs and apply its overlay.[1]

```nix
{
  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    nix-cachyos-kernel.url = "github:xddxdd/nix-cachyos-kernel";
  };[1]

  outputs = { self, nixpkgs, nix-cachyos-kernel, ... }: {
    nixosConfigurations.your-hostname = nixpkgs.lib.nixosSystem {
      specialArgs = { inherit inputs; };
      modules = [
        ./configuration.nix[1]
        # Add the overlay to access the kernel packages
        {
          nixpkgs.overlays = [ nix-cachyos-kernel.overlays.default ];
        }
      ];
    };
  };
}
```[2][1]

### 2. Binary Cache (Highly Recommended)
CachyOS kernels are heavily optimized and take a long time to build.[1] Add these substituters to your `configuration.nix` to use pre-built binaries.

```nix
{
  nix.settings = {
    substituters = [ "https://attic.xuyh0120.win/lantian" ];
    trusted-public-keys = [ "lantian:EeAUQ+W+6r7EtwnmYjeVwx5kOGEBpjlBfPlzGlTNvHc=" ];
  };
}
```[1][2]

### 3. Kernel & NVIDIA Configuration (`configuration.nix`)
Set the kernel to a CachyOS variant and configure the NVIDIA drivers to build against it.[1]

```nix
{ config, pkgs, ... }:

{
  # 1. Set the CachyOS Kernel[2][3][4][1][5]
  # Options: linuxPackages-cachyos, linuxPackages-cachyos-lto, linuxPackages-cachyos-lts, etc.
  boot.kernelPackages = pkgs.linuxPackages-cachyos;[2][1]

  # 2. Enable NVIDIA Drivers
  services.xserver.videoDrivers = [ "nvidia" ];[1]

  hardware.nvidia = {
    # Modesetting is required for most modern setups
    modesetting.enable = true;[1]

    # Use the NVIDIA driver package that matches your kernel[1]
    # 'stable' or 'beta' are usually recommended for CachyOS
    package = config.boot.kernelPackages.nvidiaPackages.stable;[1]

    # Enable the Nvidia settings menu
    nvidiaSettings = true;[1]

    # Power management (optional, helps with suspend/resume)
    powerManagement.enable = false;
    powerManagement.finegrained = false;[1]

    # Use the NVidia open source kernel module (not to be confused with nouveau)[1]
    # Only available for Turing (RTX 20-series) and newer GPUs
    open = false; 
  };[1]

  # 3. Kernel Parameters for NVIDIA
  boot.kernelParams = [ 
    "nvidia-drm.modeset=1" 
    "nvidia.NVreg_PreserveVideoMemoryAllocations=1"
  ];[1]

  # 4. Allow Unfree Packages (Required for NVIDIA)
  nixpkgs.config.allowUnfree = true;
}
```[1]

### Key Considerations
*   **LTO Kernels:** If you use `linuxPackages-cachyos-lto`, be aware that some out-of-tree kernel modules (like older NVIDIA drivers or specific Wi-Fi drivers) might fail to compile.[1] The standard `linuxPackages-cachyos` is safer for compatibility.[1]
*   **Secure Boot:** If you use Secure Boot (e.g., via `lanzaboote`), you will need to sign the CachyOS kernel manually or via your automated signing setup.[1]
*   **Microarchitecture:** CachyOS kernels are often optimized for `x86-64-v3` or `v4`.[6][7][1] Ensure your CPU supports the instruction set of the package you are pulling (most CPUs from the last 5-8 years support `v3`).[1]

### Verification
After rebuilding (`sudo nixos-rebuild switch`), you can verify the kernel and driver:
```bash
uname -a           # Should show "-cachyos" in the version string
nvidia-smi         # Should show your GPU and driver version
lsmod | grep nvidia # Should show the nvidia modules loaded
```[1]

